import LOGO from "./asset/logo_thecla.png";
const ECOSWAP_LOGO = "data:image/png;base64,";
const VWATCH_LOGO = "data:image/png;base64,";
const IMG_A1 = "data:image/jpeg;base64,";
const IMG_A2 = "data:image/jpeg;base64,";

