function useSlider(arr, ms = 5000) {
  const [i, si] = useState(0);
  useEffect(() => { const t = setInterval(() => si(x => (x+1)%arr.length), ms); return()=>clearInterval(t); }, [arr.length, ms]);
  return [i, si];
}
function useFade() {
  const r = useRef(null); const [v, sv] = useState(false);
  useEffect(() => {
    const o = new IntersectionObserver(([e])=>{if(e.isIntersecting)sv(true)},{threshold:.08});
    if(r.current)o.observe(r.current); return()=>o.disconnect();
  }, []);
  return [r, v];
}
function F({children, d=0, style={}}) {
  const [r,v] = useFade();
  return <div ref={r} className={`fade ${v?"vis":""}`} style={{transitionDelay:`${d}s`,...style}}>{children}</div>;
}

function WaitlistForm() {
  const [sel, setSel] = useState([]);
  const [form, setForm] = useState({name:"",email:"",phone:""});
  const [errors, setErrors] = useState({});
  const [loading, setLoading] = useState(false);
  const [done, setDone] = useState(false);

  const toggle = id => setSel(s => s.includes(id) ? s.filter(x=>x!==id) : [...s, id]);

  const validate = () => {
    const e = {};
    if(!sel.length) e.sel = "Please select at least one product";
    if(!form.name.trim()) e.name = "Name is required";
    if(!form.email.trim() || !/\S+@\S+\.\S+/.test(form.email)) e.email = "Valid email required";
    return e;
  };

  const submit = async () => {
    const e = validate();
    if(Object.keys(e).length) { setErrors(e); return; }
    setLoading(true);
    await new Promise(r => setTimeout(r, 1400));
    setLoading(false);
    setDone(true);
  };

  if(done) return (
    <div className="wl-success">
      <div className="big">🎉</div>
      <h3>You're on the waitlist!</h3>
      <p>Thank you, <b>{form.name}</b>! We'll be in touch at <b>{form.email}</b> with early access details for <b>{sel.join(" & ")}</b>.</p>
    </div>
  );

  return (
    <div>
      <p style={{color:"var(--silver)",fontSize:".88rem",marginBottom:24,fontWeight:300}}>Select the product(s) you'd like early access to, then fill in your details.</p>
      <div className="wl-products">
        {[
          {id:"EcoSwap", label:"EcoSwap", sub:"Circular Economy App", logo:ECOSWAP_LOGO, cls:"eco-sel"},
          {id:"VirtualWatch", label:"VirtualWatch", sub:"Care Operations Platform", logo:VWATCH_LOGO, cls:"vw-sel"},
        ].map(p=>(
          <div key={p.id} className={`wl-prod ${sel.includes(p.id)?"selected":""} ${p.cls}`} onClick={()=>toggle(p.id)}>
            <img src={p.logo} alt={p.label} className="wl-prod-logo" style={{mixBlendMode:"multiply"}}/>
            <div className="wl-prod-info"><b>{p.label}</b><span>{p.sub}</span></div>
            <div className="wl-check">{sel.includes(p.id)?"✓":""}</div>
          </div>
        ))}
      </div>
      {errors.sel && <p className="wl-err">{errors.sel}</p>}
      <div className="wl-form">
        <div className="wl-row">
          <div>
            <input placeholder="Full Name *" value={form.name} onChange={e=>setForm(f=>({...f,name:e.target.value}))} />
            {errors.name && <p className="wl-err">{errors.name}</p>}
          </div>
          <div>
            <input placeholder="Email Address *" value={form.email} onChange={e=>setForm(f=>({...f,email:e.target.value}))} />
            {errors.email && <p className="wl-err">{errors.email}</p>}
          </div>
        </div>
        <input placeholder="Phone Number (optional)" value={form.phone} onChange={e=>setForm(f=>({...f,phone:e.target.value}))} />
        <button className="wl-submit" onClick={submit} disabled={loading}>
          {loading ? "Joining..." : "🚀 Join the Waitlist"}
        </button>
      </div>
    </div>
  );
}

